var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"글쎄, 해줄 말이고 자시고 도망부터 가라고!","JPN":"だから、伝えたいことも何も、逃げるのが先だってば！","ENG":"There’s no time! Just go already!","TWN":"不用啦，沒什麼好說的，先逃吧！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"아까 그 여자.","JPN":"さっきのあの女。","ENG":"That woman...","TWN":"剛剛那個女的，"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……헤론 님?","JPN":"……ヘロン様？","ENG":"You mean Madam Heron?","TWN":"……海倫夫人？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"응. 위저드에 있던 아이들…… 그리고 글린다 네 꿈에 그 여자가 나왔어.","JPN":"うん。ウィザードにいた子どもたち……そしてグリンダ、あなたの夢にもあの女がいた。","ENG":"Yes. She’s the one who appears in your dreams... and the Wizard children’s.","TWN":"嗯，在魔法師的孩子們……和你的夢裡，那個女的都曾經出現過。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"내…… 꿈에?","JPN":"私の……夢に？","ENG":"In... my dreams?","TWN":"我的……夢裡？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"네 악몽에. 널 괴롭히던 악몽이 그 여자 모습이었어.","JPN":"あなたの悪夢に。グリンダを苦しめた悪夢があの女の姿だったの。","ENG":"In your nightmare. The thing that haunted you looked just like her.","TWN":"在你的惡夢裡，折磨你的惡魔就是她。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럴 리가 없어…… 헤론 님은 항상 우리에게 다정하셨는데…….","JPN":"そんなはずない……ヘロン様はいつも私たちに優しくしてくださったんだ……","ENG":"There’s no way... But Madam Heron was so nice to us...","TWN":"怎麼可能……海倫夫人對我們都很親切……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"사람들은 자기가 누구에게 괴롭힘 당하는지 모를 수 있지.","JPN":"人は自分が誰のせいで苦しんでるのかわからないこともあるよ。","ENG":"People can’t usually tell who’s bullying them.","TWN":"人們有可能不清楚是誰在傷害自己，"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"보통은 교묘하게 자신의 책임을 회피하며 남 탓으로 모든 걸 넘겨 버리니까.","JPN":"普通は巧みに自分の責任を回避して、すべて他人のせいにしちゃうから。","ENG":"That’s because bullies avoid any responsibility and just blame it on others.","TWN":"通常都是巧妙地避開自己的責任，把一切都推卸給別人。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"하지만…… 뇌는 바보가 아니야. 무의식은 알아. ","JPN":"でも……脳はバカじゃないの。無意識は知ってる。 ","ENG":"However... The brain isn’t stupid. Your subconscious knows.","TWN":"不過……大腦不是笨蛋，潛意識裡很清楚，"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"누가 나를 힘들게 하는지, 꿈은 솔직하게 보여줄 수 있어.","JPN":"誰が自分を苦しめてるのか、夢はありのままを見せてくれる。","ENG":"It knows who’s making you suffer, and reflects it in your dreams.","TWN":"在夢裡會真實地呈現出來，是誰在折磨我。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다. 난 그런 사람 옆에 널 두고 갈 수 없어.","JPN":"グリンダ。私はそんな人のそばにあなたを置いて行けないよ。","ENG":"Glinda. I'm not going to leave you with someone like that.","TWN":"格琳達，我不能把你丟給那種人自己逃掉。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루…….","JPN":"ルル……","ENG":"Lulu...","TWN":"露露……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"휴. 재미없어.","JPN":"ふう、つまらないわね。","ENG":"Ugh... This is unamusing.","TWN":"哀～真是無聊。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"재미없는 건 헤이븐 님 성미에 그냥 내버려둘 수 없지.","JPN":"ヘイブン様の性格上、つまらないものは放っておけないのよ。","ENG":"\\"Unentertaining\\" doesn’t suit Mr. Haven’s style.","TWN":"天堂先生可無法容忍無聊。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님의 명령이에요. 저 양털 같이 축 늘어진 아이는 데려가죠.","JPN":"ヘイブン様のご命令です。あの濡れた羊毛のようにぐったりしてる子を連れて行きなさい。","ENG":"Mr. Haven’s orders. Take that woolly girl away.","TWN":"這是天堂先生的命令，把那個頭上長羊角的孩子帶走。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루를 어디로 데려가려고요!","JPN":"ルルをどこに連れて行くんですか！","ENG":"Where are you taking Lulu?!","TWN":"你們要把露露帶去哪裡！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};